VALUES
  ('social-worker-moex-01081', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作所服務的案主經常是遭遇多重問題，以及所需要的福利資源甚少單一機構足以提供。當 在從事專業服務時，只是完全按照該機構的服務規定、法令的規定、依照機構現有的資源分配給 目前的案主，這是屬於那一種型態的社會工作師？', '["反思性實務工作者", "防禦性實務工作者", "反身性實務工作者", "理性型實務工作者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01082', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '推行「性侵害案件減少被害人重複陳述方案」是希望能保障案主的權益。下列何者並非此方案的 主要目標？', '["實施生活適應講座，使案主感受安全", "整合醫療、社政、檢察和警察四大服務體系", "詢（訊）問時全程錄影錄音，以提升偵辦時效與品質", "透過會同詢（訊）問方式，減少案主的陳述總次數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01083', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '從三級預防觀點來看兒童保護工作，下列何者屬於社會工作師所執行的二級預防工作？', '["接受通報後，提供及時協助", "在幼兒園的晨間課程教導兒童自我保護技巧", "轉案後，追蹤受虐兒童的近況", "對已接受協助的受虐兒童提供長期性服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01084', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '從青少年的發展取向來看，促進青少年行使社會公民責任的做法，下列敘述何者錯誤？', '["政府應有正式的制度和機制讓青少年練習公民權的行使", "降低各種網路平台的使用年齡，以保障青少年的資訊權", "青少年發展需同時兼顧其生活環境、機會、資源與主體性", "政府應提供青少年參與公共政策討論和決策過程的平台"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01085', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於身心障礙的敘述，下列何者正確？①障礙的分類是固定不變的  ②中世紀歐洲因慈善理念進', '["文藝復興時期的歐洲開始將貧 窮與障礙議題分開處理", "19世紀啟蒙時代視障礙者為病人的醫療觀點，讓障礙者逐漸被社會所 排除  ⑤1950年代機構式缺乏人性的照顧機制備受關注，開始西方的去機構化運動", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01086', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關當前教育部補助「專任專業輔導人員」的聘任現況，下列何者錯誤？', '["專科以上學校學生1,200人以下應置專業輔導人員至少1人", "各縣市所轄高中職以下學校數合計20所學校以下者置1人", "高中職以下學校，其班級數達50班以上應至少置1人", "高中職以下學校，其班級數達55班以上應至少置1人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01087', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會及社區變遷方案是職業社會工作（OccupationalSocialWork）服務方案的一種。下列何者不包 括在其服務內涵？', '["建立員工與附近鄰里關係的發展與維持", "工商業界回饋社區鄰里與社會的社會責任方案", "擴大公司產品、社會網絡行銷的公共關係方案", "有關行政中立訓練、公平政策與歧視預防的肯定行動方案（affirmativeaction）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01088', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '為因應醫學進步、社會變遷及高齡化趨勢，在健康照護社會工作上，可能出現那些服務型態的轉', '["以醫療院所患者的服務為重", "逐漸重視連續照顧與全人照顧", "投入更多對於改善健 康不平等的倡導工作", "病人的主體意識提升促進了醫病溝通"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01089', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '為因應新興社會問題，臺灣近年推動各種「以社區為基礎」的服務方案。下列何者較不具備前述 特性？', '["長期照顧十年計畫2.0", "強化社會安全網計畫", "預防及延緩失能照護計畫", "社會工作人員執業安全方案"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01090', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '面對申請多個公、私社福單位補助的案主，下列敘述何者接近「每個人生來就有能量與動機追求 改變」？', '["案主對福利規定熟稔，具備處理複雜事務能力", "各機構間缺乏聯繫，案主在機構間鑽漏洞", "濫用社福資源，應嚴審避免養成福利依賴", "量表與標準化評估指標，可避免資源運用無效率"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
